class Custom_User_Authentication {
    
    private static $instance = null;
    private $table_name;
    
    public static function get_instance() {
        if (self::$instance == null) {
            self::$instance = new Custom_User_Authentication();
        }
        return self::$instance;
    }
    
    private function __construct() {
        global $wpdb;
        $this->table_name = $wpdb->prefix . 'custom_auth_users';
        
        register_activation_hook(__FILE__, array($this, 'activate'));
        add_action('init', array($this, 'init'));
        add_shortcode('custom_register', array($this, 'registration_form'));
        add_shortcode('custom_login', array($this, 'login_form'));
        add_action('wp_ajax_nopriv_custom_register', array($this, 'handle_registration'));
        add_action('wp_ajax_nopriv_custom_login', array($this, 'handle_login'));
        add_action('wp_ajax_custom_logout', array($this, 'handle_logout'));
        add_action('wp_enqueue_scripts', array($this, 'enqueue_scripts'));
    }
    
    public function activate() {
        global $wpdb;
        $charset_collate = $wpdb->get_charset_collate();
        
        $sql = "CREATE TABLE IF NOT EXISTS {$this->table_name} (
            id bigint(20) NOT NULL AUTO_INCREMENT,
            username varchar(60) NOT NULL,
            email varchar(100) NOT NULL,
            password_hash varchar(255) NOT NULL,
            created_at datetime DEFAULT CURRENT_TIMESTAMP,
            last_login datetime DEFAULT NULL,
            status varchar(20) DEFAULT 'active',
            PRIMARY KEY (id),
            UNIQUE KEY username (username),
            UNIQUE KEY email (email)
        ) $charset_collate;";
        
        require_once(ABSPATH . 'wp-admin/includes/upgrade.php');
        dbDelta($sql);
    }
    
    public function init() {
        session_start();
    }
    
    public function enqueue_scripts() {
        wp_enqueue_style('custom-auth-style', plugin_dir_url(__FILE__) . 'css/custom-auth.css');
        wp_enqueue_script('custom-auth-script', plugin_dir_url(__FILE__) . 'js/custom-auth.js', array('jquery'), '1.0', true);
        wp_localize_script('custom-auth-script', 'customAuth', array(
            'ajaxurl' => admin_url('admin-ajax.php'),
            'nonce' => wp_create_nonce('custom_auth_nonce')
        ));
    }
    
    public function hash_password($password) {
        return password_hash($password, PASSWORD_BCRYPT, array('cost' => 12));
    }
    
    public function verify_password($password, $hash) {
        return password_verify($password, $hash);
    }
    
    public function registration_form() {
        if ($this->is_user_logged_in()) {
            return '<div class="custom-auth-message">You are already logged in.</div>';
        }
        
        ob_start();
        ?>
        <div class="custom-auth-container">
            <form id="custom-register-form" class="custom-auth-form">
                <h2>Register</h2>
                <div class="custom-auth-message" id="register-message"></div>
                
                <div class="form-group">
                    <label for="register-username">Username</label>
                    <input type="text" id="register-username" name="username" required>
                </div>
                
                <div class="form-group">
                    <label for="register-email">Email</label>
                    <input type="email" id="register-email" name="email" required>
                </div>
                
                <div class="form-group">
                    <label for="register-password">Password</label>
                    <input type="password" id="register-password" name="password" required>
                </div>
                
                <div class="form-group">
                    <label for="register-confirm-password">Confirm Password</label>
                    <input type="password" id="register-confirm-password" name="confirm_password" required>
                </div>
                
                <div class="form-group">
                    <button type="submit" class="custom-auth-button">Register</button>
                </div>
            </form>
        </div>
        <?php
        return ob_get_clean();
    }
    
    public function login_form() {
        if ($this->is_user_logged_in()) {
            $user = $this->get_current_user();
            ob_start();
            ?>
            <div class="custom-auth-container">
                <div class="custom-auth-message success">
                    Welcome, <?php echo esc_html($user['username']); ?>!
                    <form id="custom-logout-form" style="display:inline;">
                        <button type="submit" class="custom-auth-button">Logout</button>
                    </form>
                </div>
            </div>
            <?php
            return ob_get_clean();
        }
        
        ob_start();
        ?>
        <div class="custom-auth-container">
            <form id="custom-login-form" class="custom-auth-form">
                <h2>Login</h2>
                <div class="custom-auth-message" id="login-message"></div>
                
                <div class="form-group">
                    <label for="login-username">Username or Email</label>
                    <input type="text" id="login-username" name="username" required>
                </div>
                
                <div class="form-group">
                    <label for="login-password">Password</label>
                    <input type="password" id="login-password" name="password" required>
                </div>
                
                <div class="form-group">
                    <button type="submit" class="custom-auth-button">Login</button>
                </div>
            </form>
        </div>
        <?php
        return ob_get_clean();
    }
    
    public function handle_registration() {
        check_ajax_referer('custom_auth_nonce', 'nonce');
        
        $username = sanitize_text_field($_POST['username']);
        $email = sanitize_email($_POST['email']);
        $password = $_POST['password'];
        $confirm_password = $_POST['confirm_password'];
        
        if (empty($username) || empty($email) || empty($password) || empty($confirm_password)) {
            wp_send_json_error(array('message' => 'All fields are required.'));
        }
        
        if (!is_email($email)) {
            wp_send_json_error(array('message' => 'Invalid email address.'));
        }
        
        if (strlen($username) < 3) {
            wp_send_json_error(array('message' => 'Username must be at least 3 characters.'));
        }
        
        if (strlen($password) < 6) {
            wp_send_json_error(array('message' => 'Password must be at least 6 characters.'));
        }
        
        if ($password !== $confirm_password) {
            wp_send_json_error(array('message' => 'Passwords do not match.'));
        }
        
        if ($this->username_exists($username)) {
            wp_send_json_error(array('message' => 'Username already exists.'));
        }
        
        if ($this->email_exists($email)) {
            wp_send_json_error(array('message' => 'Email already exists.'));
        }
        
        $password_hash = $this->hash_password($password);
        
        global $wpdb;
        $result = $wpdb->insert(
            $this->table_name,
            array(
                'username' => $username,
                'email' => $email,
                'password_hash' => $password_hash,
                'created_at' => current_time('mysql'),
                'status' => 'active'
            ),
            array('%s', '%s', '%s', '%s', '%s')
        );
        
        if ($result) {
            wp_send_json_success(array('message' => 'Registration successful! You can now login.'));
        } else {
            wp_send_json_error(array('message' => 'Registration failed. Please try again.'));
        }
    }
    
    public function handle_login() {
        check_ajax_referer('custom_auth_nonce', 'nonce');
        
        $username = sanitize_text_field($_POST['username']);
        $password = $_POST['password'];
        
        if (empty($username) || empty($password)) {
            wp_send_json_error(array('message' => 'Username and password are required.'));
        }
        
        $user = $this->get_user_by_username_or_email($username);
        
        if (!$user) {
            wp_send_json_error(array('message' => 'Invalid username or password.'));
        }
        
        if ($user['status'] !== 'active') {
            wp_send_json_error(array('message' => 'Your account is not active.'));
        }
        
        if (!$this->verify_password($password, $user['password_hash'])) {
            wp_send_json_error(array('message' => 'Invalid username or password.'));
        }
        
        global $wpdb;
        $wpdb->update(
            $this->table_name,
            array('last_login' => current_time('mysql')),
            array('id' => $user['id']),
            array('%s'),
            array('%d')
        );
        
        $_SESSION['custom_auth_user_id'] = $user['id'];
        $_SESSION['custom_auth_username'] = $user['username'];
        
        wp_send_json_success(array(
            'message' => 'Login successful!',
            'redirect' => home_url()
        ));
    }
    
    public function handle_logout() {
        check_ajax_referer('custom_auth_nonce', 'nonce');
        
        unset($_SESSION['custom_auth_user_id']);
        unset($_SESSION['custom_auth_username']);
        session_destroy();
        
        wp_send_json_success(array(
            'message' => 'Logged out successfully!',
            'redirect' => home_url()
        ));
    }
    
    private function username_exists($username) {
        global $wpdb;
        $count = $wpdb->get_var($wpdb->prepare(
            "SELECT COUNT(*) FROM {$this->table_name} WHERE username = %s",
            $username
        ));
        return $count > 0;
    }
    
    private function email_exists($email) {
        global $wpdb;
        $count = $wpdb->get_var($wpdb->prepare(
            "SELECT COUNT(*) FROM {$this->table_name} WHERE email = %s",
            $email
        ));
        return $count > 0;
    }
    
    private function get_user_by_username_or_email($username_or_email) {
        global $wpdb;
        $user = $wpdb->get_row($wpdb->prepare(
            "SELECT * FROM {$this->table_name} WHERE username = %s OR email = %s",
            $username_or_email,
            $username_or_email
        ), ARRAY_A);
        return $user;
    }
    
    public function is_user_logged_in() {
        return isset($_SESSION['custom_auth_user_id']) && !empty($_SESSION['custom_auth_user_id']);
    }
    
    public function get_current_user() {
        if (!$this->is_user_logged_in()) {
            return null;
        }
        
        global $wpdb;
        $user = $wpdb->get_row($wpdb->prepare(
            "SELECT * FROM {$this->table_name} WHERE id = %d",
            $_SESSION['custom_auth_user_id']
        ), ARRAY_A);
        
        return $user;
    }
}

