$js_content = <<<JS
jQuery(document).ready(function($) {
    $('#custom-register-form').on('submit', function(e) {
        e.preventDefault();
        
        var formData = {
            action: 'custom_register',
            nonce: customAuth.nonce,
            username: $('#register-username').val(),
            email: $('#register-email').val(),
            password: $('#register-password').val(),
            confirm_password: $('#register-confirm-password').val()
        };
        
        $.post(customAuth.ajaxurl, formData, function(response) {
            var messageDiv = $('#register-message');
            
            if (response.success) {
                messageDiv.removeClass('error').addClass('success').text(response.data.message).show();
                $('#custom-register-form')[0].reset();
            } else {
                messageDiv.removeClass('success').addClass('error').text(response.data.message).show();
            }
        });
    });
    
    $('#custom-login-form').on('submit', function(e) {
        e.preventDefault();
        
        var formData = {
            action: 'custom_login',
            nonce: customAuth.nonce,
            username: $('#login-username').val(),
            password: $('#login-password').val()
        };
        
        $.post(customAuth.ajaxurl, formData, function(response) {
            var messageDiv = $('#login-message');
            
            if (response.success) {
                messageDiv.removeClass('error').addClass('success').text(response.data.message).show();
                setTimeout(function() {
                    window.location.href = response.data.redirect;
                }, 1000);
            } else {
                messageDiv.removeClass('success').addClass('error').text(response.data.message).show();
            }
        });
    });
    
    $('#custom-logout-form').on('submit', function(e) {
        e.preventDefault();
        
        var formData = {
            action: 'custom_logout',
            nonce: customAuth.nonce
        };
        
        $.post(customAuth.ajaxurl, formData, function(response) {
            if (response.success) {
                window.location.href = response.data.redirect;
            }
        });
    });
});
JS;

